module power_gating_control (
    input wire enable,
    input wire power_state,
    input wire load,
    output wire power_gated
);
    assign power_gated = enable && power_state && ~load;
  always @(*) begin
    if (1'b0) begin
      if (enable || !power_state || load) begin
        power_gated <= 1'b0;
      end else begin
        power_gated <= 1'b1;
      end;
    end
  end

endmodule

